void mainImage(out vec4 Q, vec2 U)
{
    float f = iResolution.y / 1.;
    vec2 O = floor(iResolution.xy / 2.);
    vec2 V = (U - O - .5) / f;
    vec4 M = (abs(iMouse) - O.xyxy) / f;
    float a = iTime / 5.;
    float e = .5;
    if (length(iMouse.zw) > 10.)
    {
        a = atan(M.y, M.x);
        e = length(M.xy);
    }
    mat2 R = mat2(cos(a), sin(a), -sin(a), cos(a));
    mat2 S = mat2(exp(-e), 0, 0, exp(e));
    //V = R * S * transpose(R) * V;
    float c2 = cos(a) * cos(a);
    float s2 = sin(a) * sin(a);
    V = mat2(c2*exp(-e) + s2*exp(e), -sin(2.*a)*sinh(e), -sin(2.*a)*sinh(e), c2*exp(e) + s2*exp(-e)) * V;
    Q = vec4(1);
    Q = mix(texture(iChannel0, V - .5, -abs(e)), Q, .6);
    Q = mix(vec4(1, 0, 0, 1), Q, clamp(abs(V.x) * f * .7, 0., 1.));
    Q = mix(vec4(1, 0, 0, 1), Q, clamp(abs(V.y) * f * .7, 0., 1.));
    Q = mix(vec4(1, .5, 0, 1), Q, clamp(length(length(V) - .3) * f - 1., 0., 1.));
}
